8	type QuoteResult = { premium: number };
9	type Output = { results: QuoteResult[] };
10	
11	const basePremium = (item: Item): number => {
12	  if (item.type === "sword") return 100;
13	  if (item.type === "amulet") return 60;
14	  return 0;
15	};
16	
17	const quote = (step: QuoteStep): QuoteResult => {
18	  const base = step.items.reduce((sum, item) => sum + basePremium(item), 0);
19	  const firstInsurance = base * FIRST_INSURANCE_RATE;
20	  return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
21	};
22	
23	export const run = (input: unknown): Output => {
24	  const scenario = input as Scenario;
25	  return { results: scenario.steps.map(quote) };
26	};
